  const fromEmail = body.fromEmail || DEFAULT_FROM_EMAIL;
  const emailSubject = body.emailSubject || 'Azure Function Test Email';
  const emailText = body.emailText || 'Hello from Azure Function using SendGrid.';
  const emailHtml = body.emailHtml || `<p>${emailText}</p>`;

